// Decision framework for resolving deadlocked technical disagreements

function resolveTechnicalDisagreement(
  proposalA: string,
  proposalB: string,
  criteria: string[]
): ResolutionStrategy {
  const canExperiment = criteria.every(c => measureableInWeeks(c, 4));

  if (canExperiment) {
    return {
      strategy: "timeboxedExperiment",
      plan: {
        duration: "4 weeks",
        teams: ["Team A runs proposal A", "Team B runs proposal B"],
        successCriteria: criteria,
        decisionRule: "Adopt approach that meets more criteria at end of experiment"
      }
    };
  }

  // If experiment is infeasible, escalate to designated decider
  return {
    strategy: "disagreeAndCommit",
    plan: {
      decider: "Principal Engineer or Eng Director",
      documentRequired: true,
      commitment: "Both parties sign commitment to support chosen approach",
      postMortem: "Scheduled 3 months after decision regardless of outcome"
    }
  };
}
